INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1000101, "ふっふっふ、これでカヤぴぃとボスを見返してやるです！", "vo_minigame_1004", 2, 10001, "vo_minigame_1004_top_1_000");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1000201, "しりとりでの戦い、お兄さんにも手伝ってもらうです", "vo_minigame_1004", 2, 10002, "vo_minigame_1004_top_1_003");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1000301, "どんなケンカも売られた以上は買うのが喧嘩屋だ！やってやるぜ！", "vo_minigame_1004", 1, 10003, "vo_minigame_1004_top_1_004");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1000401, "石板でしりとりか……イノリのヤツおもしろいこと考えるな", "vo_minigame_1004", 1, 10004, "vo_minigame_1004_top_1_005");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1000501, "しりとりだろうがなんだろうが返り討ちにしてやるぜ", "vo_minigame_1004", 1, 10005, "vo_minigame_1004_top_1_006");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1000601, "ぐもも……（オデ、ハラヘッタ）", "vo_minigame_1004", 2, 10006, "vo_minigame_1004_top_1_007");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1000701, "ぐもももも（シリトリ タノシイ）", "vo_minigame_1004", 2, 10007, "vo_minigame_1004_top_1_008");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1000801, "ぐもももも！（イノリ イイヤツ）", "vo_minigame_1004", 2, 10008, "vo_minigame_1004_top_1_009");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1000901, "カヤぴぃ相手でも手加減しないです", "vo_minigame_1004", 2, 10009, "vo_minigame_1004_top_2_010");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1000902, "上等だ！やるからには本気で来いよな", "vo_minigame_1004", 1, 10009, "vo_minigame_1004_top_2_011");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1001001, "カヤぴぃ、謝るなら今のうちです", "vo_minigame_1004", 2, 10010, "vo_minigame_1004_top_2_012");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001002, "イノリこそ泣きを入れるなら今のうちだぜ？", "vo_minigame_1004", 1, 10010, "vo_minigame_1004_top_2_013");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1001101, "カヤぴぃ、これからは知性の時代ですよ？", "vo_minigame_1004", 2, 10011, "vo_minigame_1004_top_2_014");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001102, "待て！オレがバカみたいにいうな！！", "vo_minigame_1004", 1, 10011, "vo_minigame_1004_top_2_015");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1001201, "さあ、あたしたちの力を見せてやるです", "vo_minigame_1004", 1, 10012, "vo_minigame_1004_top_2_016");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1001202, "ぐも！（マカセロ！）", "vo_minigame_1004", 2, 10012, "vo_minigame_1004_top_2_017");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1001301, "よしよし、いいですようまくできたらチョコをあげるです！", "vo_minigame_1004", 1, 10013, "vo_minigame_1004_top_2_018");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1001302, "ぐも！（オデ チョコスキ）", "vo_minigame_1004", 2, 10013, "vo_minigame_1004_top_2_019");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001401, "なあイノリ……もしかして当初の目的見失ってないよな？", "vo_minigame_1004", 1, 10014, "vo_minigame_1004_top_2_023");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1001402, "もちろん覚えてるですカヤぴぃを倒し我々の知能を証明するです", "vo_minigame_1004", 2, 10014, "vo_minigame_1004_top_2_024");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001501, "いくらイノリ相手でも勝ちを譲る気はないからな！", "vo_minigame_1004", 1, 10015, "vo_minigame_1004_top_2_025");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1001502, "望むところです手加減はなしですよ", "vo_minigame_1004", 2, 10015, "vo_minigame_1004_top_2_026");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001601, "へっ、なかなかやるじゃねえか", "vo_minigame_1004", 1, 10016, "vo_minigame_1004_top_2_027");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1001602, "カヤぴぃも思ったよりやるですね！", "vo_minigame_1004", 2, 10016, "vo_minigame_1004_top_2_028");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001701, "お～い、ドラゴンもどき？", "vo_minigame_1004", 1, 10017, "vo_minigame_1004_top_2_029");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1001702, "ぐもっ！？（ヒッ！）", "vo_minigame_1004", 2, 10017, "vo_minigame_1004_top_2_030");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001801, "いやあ、あんときは悪かったなはっはっは", "vo_minigame_1004", 1, 10018, "vo_minigame_1004_top_2_031");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1001802, "ぐももも……（かやピィ コワカッタ）", "vo_minigame_1004", 2, 10018, "vo_minigame_1004_top_2_032");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1001901, "お前ってさ……ほんとマヌケな顔してるよな", "vo_minigame_1004", 1, 10019, "vo_minigame_1004_top_2_033");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1001902, "ぐも……（オマエガ イウカ）", "vo_minigame_1004", 2, 10019, "vo_minigame_1004_top_2_034");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1002001, "ぐも……（ハラヘッタ チョコホシイ）", "vo_minigame_1004", 2, 10020, "vo_minigame_1004_top_2_044");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1002002, "なんだ？眠いのか？", "vo_minigame_1004", 1, 10020, "vo_minigame_1004_top_2_045");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1002101, "ぐもも（コイツ……キケン）", "vo_minigame_1004", 2, 10021, "vo_minigame_1004_top_2_046");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1002102, "うん？　なんだ？オレの舎弟にでもなりたいのか？", "vo_minigame_1004", 1, 10021, "vo_minigame_1004_top_2_047");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1002201, "ぐも…（かやピィノウキン）", "vo_minigame_1004", 2, 10022, "vo_minigame_1004_top_2_048");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1002202, "おい、今失礼なこと考えてるだろ？", "vo_minigame_1004", 1, 10022, "vo_minigame_1004_top_2_049");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1002301, "なあ、これいつまで続けるんだ？", "vo_minigame_1004", 1, 10023, "vo_minigame_1004_top_3_058");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1002302, "カヤぴぃが降参するまでです！", "vo_minigame_1004", 2, 10023, "vo_minigame_1004_top_3_059");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1002303, "ぐもも！（コウサンシロ！）", "vo_minigame_1004", 2, 10023, "vo_minigame_1004_top_3_060");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1002401, "ぐも！（イノリ チョコホシイ）", "vo_minigame_1004", 2, 10024, "vo_minigame_1004_top_3_065");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1002402, "しょうがないですね、食べ過ぎはダメですよ", "vo_minigame_1004", 1, 10024, "vo_minigame_1004_top_3_066");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1002403, "土産のチョコ、そうとう気に入ったみたいだな", "vo_minigame_1004", 1, 10024, "vo_minigame_1004_top_3_067");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (3, 1002501, "ぐも！（かやピィニハ マケナイ！）", "vo_minigame_1004", 2, 10025, "vo_minigame_1004_top_3_068");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (2, 1002502, "お？なんだ？腹でも減ってるのか？", "vo_minigame_1004", 1, 10025, "vo_minigame_1004_top_3_069");
INSERT INTO `v1_c134696b3d0b154cc052d3bd9be5207c3c5606ff82a7912ca22041783954f829` VALUES (1, 1002503, "……全然話が通じてないです", "vo_minigame_1004", 2, 10025, "vo_minigame_1004_top_3_070");
